import{_ as l,o as i,c as e,a9 as s}from"./chunks/framework.STMWz9Nm.js";const k=JSON.parse('{"title":"常见垃圾收集器","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/03-JVM与性能调优/06-常见垃圾收集器.md","filePath":"语言/java/03-JVM与性能调优/06-常见垃圾收集器.md","lastUpdated":1777106511000}'),h={name:"语言/java/03-JVM与性能调优/06-常见垃圾收集器.md"};function r(t,a,d,n,p,o){return i(),e("div",null,[...a[0]||(a[0]=[s(`<h1 id="常见垃圾收集器" tabindex="-1">常见垃圾收集器 <a class="header-anchor" href="#常见垃圾收集器" aria-label="Permalink to “常见垃圾收集器”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>垃圾收集器是在 GC 算法基础上实现的具体回收器。<br> 它们面向不同目标，比如吞吐优先、低停顿优先或更大堆支持。</p><p>一句话理解：</p><ul><li>GC 算法回答的是“怎么回收”</li><li>垃圾收集器回答的是“在真实 JVM 里怎么把这些算法组织起来”</li></ul><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>不同业务场景对这些指标的要求并不一样：</p><ul><li>停顿时间</li><li>吞吐量</li><li>堆大小</li><li>CPU 资源占用</li></ul><p>理解收集器差异，才能做出更合理的选择。<br> 否则就很容易出现这种情况：</p><ul><li>盲目追求“最新”</li><li>或者长期抱着不适合当前业务的收集器不放</li></ul><h2 id="_3-先建立直觉-没有-放之四海而皆准-的最佳收集器" tabindex="-1">3. 先建立直觉：没有“放之四海而皆准”的最佳收集器 <a class="header-anchor" href="#_3-先建立直觉-没有-放之四海而皆准-的最佳收集器" aria-label="Permalink to “3. 先建立直觉：没有“放之四海而皆准”的最佳收集器”">​</a></h2><p>垃圾收集器之间的差异，本质上是在不同目标之间做权衡，例如：</p><ul><li>更高吞吐</li><li>更低停顿</li><li>更大堆下可接受的延迟</li><li>更可预测的响应时间</li></ul><p>所以你要避免一种误区：</p><ul><li>把“新不新”当成唯一标准</li></ul><p>真正的问题是：</p><ul><li>这个收集器适不适合你的业务延迟目标和资源条件</li></ul><h2 id="_4-核心内容" tabindex="-1">4. 核心内容 <a class="header-anchor" href="#_4-核心内容" aria-label="Permalink to “4. 核心内容”">​</a></h2><h3 id="_4-1-serial" tabindex="-1">4.1 Serial <a class="header-anchor" href="#_4-1-serial" aria-label="Permalink to “4.1 Serial”">​</a></h3><p><code>Serial</code> 收集器可以理解成：</p><ul><li>单线程执行 GC</li></ul><p>特点：</p><ul><li>实现简单</li><li>额外开销低</li><li>Stop-The-World 停顿期间只有一个 GC 线程工作</li></ul><p>适合：</p><ul><li>小堆</li><li>单机简单程序</li><li>对吞吐和停顿要求不高的场景</li></ul><h3 id="_4-2-parallel" tabindex="-1">4.2 Parallel <a class="header-anchor" href="#_4-2-parallel" aria-label="Permalink to “4.2 Parallel”">​</a></h3><p><code>Parallel</code> 收集器更偏向：</p><ul><li>吞吐优先</li></ul><p>特点：</p><ul><li>GC 阶段利用多线程并行回收</li><li>更适合批处理、计算型等更关注总体吞吐的场景</li></ul><p>适合：</p><ul><li>不特别追求极低停顿</li><li>更重视总体处理量</li></ul><h3 id="_4-3-cms" tabindex="-1">4.3 CMS <a class="header-anchor" href="#_4-3-cms" aria-label="Permalink to “4.3 CMS”">​</a></h3><p><code>CMS</code>（Concurrent Mark Sweep）是历史上非常重要的低停顿收集器。<br> 它的价值在于：</p><ul><li>让老年代回收更偏向并发进行</li><li>尽量缩短停顿时间</li></ul><p>但要注意：</p><ul><li>CMS 已经是历史收集器</li><li>在现代 JDK 中已被移除，不再是主流选择</li></ul><p>学习它的意义主要在于：</p><ul><li>理解低停顿收集器的发展脉络</li><li>理解为什么后来会有 G1、ZGC 这类更现代方案</li></ul><h3 id="_4-4-g1" tabindex="-1">4.4 G1 <a class="header-anchor" href="#_4-4-g1" aria-label="Permalink to “4.4 G1”">​</a></h3><p><code>G1</code> 可以理解成：</p><ul><li>面向服务端通用场景的现代收集器</li></ul><p>它的重要特点是：</p><ul><li>把堆划分为多个 Region</li><li>更强调可预测停顿目标</li><li>能同时兼顾较大堆和较平衡的表现</li></ul><p>在很多现代 JDK 环境里，它是非常常见的默认或首选候选。</p><p>适合：</p><ul><li>通用服务端应用</li><li>希望在吞吐和停顿之间取得较均衡表现</li></ul><h3 id="_4-5-zgc" tabindex="-1">4.5 ZGC <a class="header-anchor" href="#_4-5-zgc" aria-label="Permalink to “4.5 ZGC”">​</a></h3><p><code>ZGC</code> 更偏向：</p><ul><li>超低停顿</li><li>大堆场景</li></ul><p>特点：</p><ul><li>把停顿时间控制得更低</li><li>更适合对响应延迟极其敏感的应用</li></ul><p>但也要注意：</p><ul><li>它不是“所有场景都自动最好”</li><li>仍然要结合硬件、JDK 版本和业务目标判断</li></ul><h2 id="_5-常见收集器怎么对比" tabindex="-1">5. 常见收集器怎么对比 <a class="header-anchor" href="#_5-常见收集器怎么对比" aria-label="Permalink to “5. 常见收集器怎么对比”">​</a></h2><table tabindex="0"><thead><tr><th>收集器</th><th>更偏向的目标</th><th>典型印象</th></tr></thead><tbody><tr><td><code>Serial</code></td><td>简单、小堆</td><td>单线程回收，容易理解</td></tr><tr><td><code>Parallel</code></td><td>吞吐优先</td><td>关注总体处理能力</td></tr><tr><td><code>CMS</code></td><td>低停顿（历史方案）</td><td>重要但已逐步退出主流</td></tr><tr><td><code>G1</code></td><td>平衡型、可预测停顿</td><td>现代服务端常见选择</td></tr><tr><td><code>ZGC</code></td><td>超低停顿</td><td>更适合低延迟和大堆</td></tr></tbody></table><h2 id="_6-学习重点" tabindex="-1">6. 学习重点 <a class="header-anchor" href="#_6-学习重点" aria-label="Permalink to “6. 学习重点”">​</a></h2><p>这一章最重要的是掌握这些判断：</p><ul><li>收集器不是越新越一定适合</li><li>吞吐优先和低延迟优先通常很难同时极致满足</li><li>G1 是现代通用型很强的选择</li><li>ZGC 更偏低停顿目标</li><li>CMS 的价值更多在理解历史演进</li></ul><h2 id="_7-常见问题" tabindex="-1">7. 常见问题 <a class="header-anchor" href="#_7-常见问题" aria-label="Permalink to “7. 常见问题”">​</a></h2><h3 id="_7-1-盲目追求最新收集器" tabindex="-1">7.1 盲目追求最新收集器 <a class="header-anchor" href="#_7-1-盲目追求最新收集器" aria-label="Permalink to “7.1 盲目追求最新收集器”">​</a></h3><p>如果业务规模不大、延迟目标也不严苛，盲目切换未必有收益。</p><h3 id="_7-2-不结合硬件和业务延迟要求做判断" tabindex="-1">7.2 不结合硬件和业务延迟要求做判断 <a class="header-anchor" href="#_7-2-不结合硬件和业务延迟要求做判断" aria-label="Permalink to “7.2 不结合硬件和业务延迟要求做判断”">​</a></h3><p>收集器选择从来不是脱离场景的“理论最优”问题。</p><h3 id="_7-3-把收集器问题和代码问题完全割裂" tabindex="-1">7.3 把收集器问题和代码问题完全割裂 <a class="header-anchor" href="#_7-3-把收集器问题和代码问题完全割裂" aria-label="Permalink to “7.3 把收集器问题和代码问题完全割裂”">​</a></h3><p>垃圾收集器再先进，也救不了：</p><ul><li>对象疯狂膨胀</li><li>生命周期设计极差</li><li>内存泄漏</li></ul><h2 id="_8-动手验证" tabindex="-1">8. 动手验证 <a class="header-anchor" href="#_8-动手验证" aria-label="Permalink to “8. 动手验证”">​</a></h2><p>这一节可以直接操作，不需要自己额外写复杂代码。</p><h3 id="_8-1-先确认当前-jdk-可用收集器" tabindex="-1">8.1 先确认当前 JDK 可用收集器 <a class="header-anchor" href="#_8-1-先确认当前-jdk-可用收集器" aria-label="Permalink to “8.1 先确认当前 JDK 可用收集器”">​</a></h3><p>你可以直接运行这些命令：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -XX:+UseSerialGC</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xlog:gc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -XX:+UseParallelGC</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xlog:gc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -XX:+UseG1GC</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xlog:gc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -XX:+UseZGC</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xlog:gc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -version</span></span></code></pre></div><h3 id="_8-2-你应该观察到什么" tabindex="-1">8.2 你应该观察到什么 <a class="header-anchor" href="#_8-2-你应该观察到什么" aria-label="Permalink to “8.2 你应该观察到什么”">​</a></h3><p>在当前环境里，我实际验证到了这些结果：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Using Serial</span></span>
<span class="line"><span>Using Parallel</span></span>
<span class="line"><span>Using G1</span></span>
<span class="line"><span>Using The Z Garbage Collector</span></span></code></pre></div><p>它们会出现在对应命令输出的 GC 日志里。</p><h3 id="_8-3-每一条命令在验证什么" tabindex="-1">8.3 每一条命令在验证什么 <a class="header-anchor" href="#_8-3-每一条命令在验证什么" aria-label="Permalink to “8.3 每一条命令在验证什么”">​</a></h3><ul><li><code>UseSerialGC</code>：说明 JVM 确实切到了 Serial 收集器</li><li><code>UseParallelGC</code>：说明 JVM 确实切到了 Parallel 收集器</li><li><code>UseG1GC</code>：说明 JVM 确实切到了 G1</li><li><code>UseZGC</code>：说明当前 JDK 环境支持 ZGC，并且能成功启用</li></ul><h3 id="_8-4-如果你想进一步观察收集行为" tabindex="-1">8.4 如果你想进一步观察收集行为 <a class="header-anchor" href="#_8-4-如果你想进一步观察收集行为" aria-label="Permalink to “8.4 如果你想进一步观察收集行为”">​</a></h3><p>可以配合一个简单程序和 GC 日志一起看，例如：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">java</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -XX:+UseG1GC</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xms32m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xmx32m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xlog:gc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SomeDemo</span></span></code></pre></div><p>这样你就不只是看到“启用了谁”，还可以继续观察：</p><ul><li>GC 日志格式</li><li>停顿阶段</li><li>堆变化</li></ul><h3 id="_8-5-关于-cms-的特别说明" tabindex="-1">8.5 关于 CMS 的特别说明 <a class="header-anchor" href="#_8-5-关于-cms-的特别说明" aria-label="Permalink to “8.5 关于 CMS 的特别说明”">​</a></h3><p>如果你在现代 JDK 里尝试直接启用 CMS，可能会发现：</p><ul><li>参数不再可用</li><li>或行为与旧版本资料不一致</li></ul><p>这正好说明：</p><ul><li>学习 CMS 更应该站在“历史理解”和“原理对比”上</li><li>不要机械照搬旧资料到新版本生产环境</li></ul><h2 id="_9-练习建议" tabindex="-1">9. 练习建议 <a class="header-anchor" href="#_9-练习建议" aria-label="Permalink to “9. 练习建议”">​</a></h2><p>下面这些练习做完，这一章会更扎实：</p><ul><li>整理一张常见收集器对比表</li><li>用相同程序分别切换 G1、Parallel、Serial，观察日志差异</li><li>总结自己业务更在意吞吐还是延迟</li><li>结合当前 JDK 版本重新审视旧文档里的 CMS 经验</li></ul><h2 id="_10-自测问题" tabindex="-1">10. 自测问题 <a class="header-anchor" href="#_10-自测问题" aria-label="Permalink to “10. 自测问题”">​</a></h2><ul><li><code>CMS</code>、<code>G1</code>、<code>ZGC</code> 各自更偏向解决什么问题？</li><li>吞吐优先和低延迟优先为什么难以同时极致满足？</li><li>为什么垃圾收集器选择必须结合场景？</li><li>为什么说 CMS 在现代 JDK 中更多是历史理解对象？</li></ul><h2 id="_11-自测核对要点" tabindex="-1">11. 自测核对要点 <a class="header-anchor" href="#_11-自测核对要点" aria-label="Permalink to “11. 自测核对要点”">​</a></h2><p>如果你的回答能覆盖下面这些点，说明这一章基本掌握到位了：</p><ul><li>收集器是算法在 JVM 中的具体工程实现</li><li><code>Serial</code> 偏简单，<code>Parallel</code> 偏吞吐，<code>G1</code> 偏平衡，<code>ZGC</code> 偏低停顿</li><li>收集器选择必须结合延迟目标、吞吐目标和堆规模</li><li>CMS 很重要，但在现代 JDK 中已经不是主流生产选择</li></ul>`,96)])])}const C=l(h,[["render",r]]);export{k as __pageData,C as default};
